    img = None
    for s in modified_ppt_screenshots:
        if s.slide_number == 14:
            img = s.image_path
            break
    if not img:
        return ("No screenshot for slide 14.", 0.0)
    prompt = (
        'Does this slide contain three columns with one of the columns having relevant bullet(s) that specifically highlights or calls out the difference between unilateral and bilateral? '
        'Respond YES or NO and briefly justify.'
